// ─── Extract core fields from the incoming webhook payload ───
const payload  = $json.body || {};
const data     = payload.data || {};

const sessionId   = payload.sessionId || '';
const msgType     = data.type || 'chat';
const from        = data.from || '';
const phoneNumber = from.replace('@c.us', '');
const body        = data.body || '';
const mediaUrl    = data.mediaUrl || null;
const fileName    = data.fileName || null;
const caption     = data.caption || '';
const mimeType    = data.mimetype || '';
const lat         = data.lat || null;
const lng         = data.lng || null;
const loc         = data.loc || '';

let category = 'text';
if (msgType === 'image')                           category = 'image';
else if (msgType === 'video')                      category = 'video';
else if (msgType === 'audio' || msgType === 'ptt') category = 'audio';
else if (msgType === 'document')                   category = 'document';
else if (msgType === 'sticker')                    category = 'sticker';
else if (msgType === 'location')                   category = 'location';

return {
  sessionId,
  phoneNumber,
  category,
  rawType: msgType,
  body,
  mediaUrl,
  fileName,
  caption,
  mimeType,
  lat,
  lng,
  loc
};

// ─── Handle TEXT messages ───
// ECHO MODE: any message starting with 'صدى' or 'echo' reflects back
const rawText   = ($json.body || '');
const text      = rawText.toLowerCase().trim();
const phone     = $json.phoneNumber;
const sessionId = $json.sessionId;

// ── Echo mode for testing ──
if (text.startsWith('صدى') || text.startsWith('echo')) {
  const echoContent = rawText.replace(/^صدى\s*/i, '').replace(/^echo\s*/i, '').trim();
  return {
    sessionId,
    phoneNumber: phone,
    replyType: 'text',
    replyText: `🔁 صدى: ${echoContent || '(رسالة فارغة)'}\nEcho: ${echoContent || '(empty)'}`
  };
}

// ── Keyword-based auto-reply ──
let reply = 'شكراً لتواصلك! سنرد عليك قريباً.\nThank you! We will reply soon.';

if (text.includes('مرحبا') || text.includes('هلا') || text.includes('hello') || text.includes('hi') || text.includes('السلام')) {
  reply = 'أهلاً وسهلاً! 👋 كيف يمكنني مساعدتك؟\nHello! 👋 How can I help you?';
} else if (text.includes('سعر') || text.includes('price') || text.includes('كم') || text.includes('تكلفة')) {
  reply = 'يرجى التواصل مع فريق المبيعات للاستفسار عن الأسعار 📋\nPlease contact our sales team for pricing info.';
} else if (text.includes('وقت') || text.includes('دوام') || text.includes('hours') || text.includes('time') || text.includes('متى')) {
  reply = 'أوقات العمل: الأحد – الخميس 9 صباحاً – 6 مساءً 🕘\nWorking hours: Sun–Thu 9 AM – 6 PM';
} else if (text.includes('مساعدة') || text.includes('help') || text.includes('مساعد')) {
  reply = 'يمكنني مساعدتك! 🤝\nأرسل "صدى <رسالة>" لاختبار البوت.\nSend "echo <message>" to test the bot.';
}

return { sessionId, phoneNumber: phone, replyType: 'text', replyText: reply };

// ─── Handle IMAGE messages ───
const phone     = $json.phoneNumber;
const sessionId = $json.sessionId;
const caption   = $json.caption || '';
const mediaUrl  = $json.mediaUrl || '';

const reply = `تم استلام صورتك 📷${caption ? ' — ' + caption : ''}\nImage received 📷${caption ? ' — ' + caption : ''}`;

// To reply with an image: set replyType to 'image' and replyImageUrl to a public URL
return {
  sessionId,
  phoneNumber: phone,
  replyType: 'text',
  replyText: reply,
  receivedMediaUrl: mediaUrl
};

// ─── Handle VIDEO messages ───
const phone     = $json.phoneNumber;
const sessionId = $json.sessionId;
const caption   = $json.caption || '';
const mediaUrl  = $json.mediaUrl || '';

const reply = `تم استلام الفيديو 🎬${caption ? ' — ' + caption : ''}\nVideo received 🎬${caption ? ' — ' + caption : ''}`;

// To reply with a video: set replyType to 'video' and replyVideoUrl
return {
  sessionId,
  phoneNumber: phone,
  replyType: 'text',
  replyText: reply,
  receivedMediaUrl: mediaUrl
};

// ─── Handle AUDIO / Voice Note messages ───
const phone     = $json.phoneNumber;
const sessionId = $json.sessionId;
const mediaUrl  = $json.mediaUrl || '';
const isVoice   = $json.rawType === 'ptt';

const reply = isVoice
  ? 'تم استلام رسالتك الصوتية 🎙️\nVoice note received 🎙️'
  : 'تم استلام الملف الصوتي 🎵\nAudio file received 🎵';

// To reply with audio: set replyType to 'audio' and replyAudioUrl
return {
  sessionId,
  phoneNumber: phone,
  replyType: 'text',
  replyText: reply,
  receivedMediaUrl: mediaUrl
};

// ─── Handle DOCUMENT messages ───
const phone     = $json.phoneNumber;
const sessionId = $json.sessionId;
const fileName  = $json.fileName || 'document';
const mediaUrl  = $json.mediaUrl || '';
const mimeType  = $json.mimeType || '';

const reply = `تم استلام الملف 📄: ${fileName}\nDocument received 📄: ${fileName}`;

// To reply with a document: set replyType to 'document', replyFileUrl, replyFileName
return {
  sessionId,
  phoneNumber: phone,
  replyType: 'text',
  replyText: reply,
  receivedMediaUrl: mediaUrl,
  fileName,
  mimeType
};

// ─── Handle STICKER messages ───
const phone     = $json.phoneNumber;
const sessionId = $json.sessionId;
const mediaUrl  = $json.mediaUrl || '';

const reply = 'تم استلام الملصق 🎯\nSticker received 🎯';

// To reply with a sticker: set replyType to 'sticker' and replyImageUrl
// (any public PNG/JPG/WebP will be converted automatically)
return {
  sessionId,
  phoneNumber: phone,
  replyType: 'text',
  replyText: reply,
  receivedMediaUrl: mediaUrl
};

// ─── Handle LOCATION messages ───
const phone     = $json.phoneNumber;
const sessionId = $json.sessionId;
const lat       = $json.lat || 0;
const lng       = $json.lng || 0;
const loc       = $json.loc || '';

const mapsLink  = `https://maps.google.com/?q=${lat},${lng}`;
const reply     = `تم استلام موقعك 📍${loc ? ' — ' + loc : ''}\n${mapsLink}\nLocation received 📍${loc ? ' — ' + loc : ''}\n${mapsLink}`;

// To reply with a location: set replyType to 'location', replyLat, replyLng, replyLocationDesc
return {
  sessionId,
  phoneNumber: phone,
  replyType: 'text',
  replyText: reply,
  receivedLat: lat,
  receivedLng: lng
};

// ─── Error Logger ───
const err = $json;
const status = err.statusCode || err.status || 'unknown';
const body   = JSON.stringify(err.body || err.message || err);
console.error(`[WhatsApp Bot] Send failed — HTTP ${status}: ${body}`);
return { error: true, status, body };
